export type ListActivityQueryResult = NonNullable<Awaited<ReturnType<typeof listActivity>>>
export type ListActivityQueryError = ErrorType<unknown>


/**
 * @summary Get recent activity feed
 */

export function useListActivity<TData = Awaited<ReturnType<typeof listActivity>>, TError = ErrorType<unknown>>(
  options?: { query?:UseQueryOptions<Awaited<ReturnType<typeof listActivity>>, TError, TData>, request?: SecondParameter<typeof customFetch>}

 ):  UseQueryResult<TData, TError> & { queryKey: QueryKey } {

  const queryOptions = getListActivityQueryOptions(options)

  const query = useQuery(queryOptions) as  UseQueryResult<TData, TError> & { queryKey: QueryKey };

  return { ...query, queryKey: queryOptions.queryKey };
}







export const getSendChatUrl = () => {




  return `/api/chat`
}

/**
 * @summary Send a message to AI chat
 */
export const sendChat = async (chatRequest: ChatRequest, options?: RequestInit): Promise<ChatResponse> => {

  return customFetch<ChatResponse>(getSendChatUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      chatRequest,)
  }
);}




export const getSendChatMutationOptions = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof sendChat>>, TError,{data: BodyType<ChatRequest>}, TContext>, request?: SecondParameter<typeof customFetch>}
): UseMutationOptions<Awaited<ReturnType<typeof sendChat>>, TError,{data: BodyType<ChatRequest>}, TContext> => {

const mutationKey = ['sendChat'];
const {mutation: mutationOptions, request: requestOptions} = options ?
      options.mutation && 'mutationKey' in options.mutation && options.mutation.mutationKey ?
      options
      : {...options, mutation: {...options.mutation, mutationKey}}
      : {mutation: { mutationKey, }, request: undefined};




      const mutationFn: MutationFunction<Awaited<ReturnType<typeof sendChat>>, {data: BodyType<ChatRequest>}> = (props) => {
          const {data} = props ?? {};

          return  sendChat(data,requestOptions)
        }






  return  { mutationFn, ...mutationOptions }}

    export type SendChatMutationResult = NonNullable<Awaited<ReturnType<typeof sendChat>>>
    export type SendChatMutationBody = BodyType<ChatRequest>
    export type SendChatMutationError = ErrorType<unknown>

    /**
 * @summary Send a message to AI chat
 */
export const useSendChat = <TError = ErrorType<unknown>,
    TContext = unknown>(options?: { mutation?:UseMutationOptions<Awaited<ReturnType<typeof sendChat>>, TError,{data: BodyType<ChatRequest>}, TContext>, request?: SecondParameter<typeof customFetch>}
 ): UseMutationResult<
        Awaited<ReturnType<typeof sendChat>>,
        TError,
        {data: BodyType<ChatRequest>},
        TContext
      > => {
      return useMutation(getSendChatMutationOptions(options));
    }

